document.addEventListener("DOMContentLoaded",(function(){const e=document.querySelector(".contact-form");e&&e.addEventListener("submit",(async function(t){t.preventDefault();const n={name:document.getElementById("contact-name").value,email:document.getElementById("contact-email").value,subject:document.getElementById("contact-subject").value,message:document.getElementById("contact-message").value},a=document.createElement("div");a.className="form-message",e.prepend(a);try{const t=await fetch("/api/forms/contact",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(n)}),c=await t.json();t.ok?(a.innerHTML=`<div class="alert alert-success">${c.message}</div>`,e.reset()):a.innerHTML=`<div class="alert alert-danger">${c.message}</div>`}catch(e){a.innerHTML='<div class="alert alert-danger">An error occurred. Please try again.</div>'}}))}));